// modules/tasks/module.contract.ts
import { defineContract } from 'aether';

export default defineContract({
  name: 'tasks',
  description: 'Handles task creation, assignment, and management utilities.',

  dependencies: { modules: ['auth'] },

  exposes: {
    routes: [
      { method: 'POST', path: '/tasks/assign', auth: true },
    ],
    functions: ['createTask', 'assignTask'],
    types: ['Task', 'AssignmentError'],
  },

  sideEffects: [
    'writes to: tasks table',
    'writes to: assignments table',
  ],

  invariants: [
    'Only team members can be assigned to a task',
  ],
});

// modules/tasks/lib/queries.ts
import { query } from '../db';
import { Task, AssignmentError } from '../../lib/types';

export async function createTask(taskData: Partial<Task>): Promise<Result<Task, AssignmentError>> {
  try {
    const result = await query('INSERT INTO tasks (title, description) VALUES ($1, $2) RETURNING *', [taskData.title, taskData.description]);
    return ok(result.rows[0] as Task);
  } catch (error) {
    return err(AssignmentError.DatabaseFailure);
  }
}

export async function assignTask(taskId: number, assigneeId: number): Promise<Result<void, AssignmentError>> {
  try {
    const result = await query('SELECT * FROM teams WHERE id IN (SELECT team_id FROM tasks WHERE id = $1)', [taskId]);
    if (result.rows.length === 0) {
      return err(AssignmentError.TaskNotFound);
    }

    const taskTeamId = result.rows[0].id;
    const assigneeResult = await query('SELECT * FROM users WHERE id = $1 AND team_id = $2', [assigneeId, taskTeamId]);
    if (assigneeResult.rows.length === 0) {
      return err(AssignmentError.AssigneeNotInTaskTeam);
    }

    await query('INSERT INTO assignments (task_id, assignee_id) VALUES ($1, $2)', [taskId, assigneeId]);
    return ok(undefined);
  } catch (error) {
    return err(AssignmentError.DatabaseFailure);
  }
}

// modules/tasks/routes/assign.ts
import { Router } from 'bun';
import { requireUser, getSession } from '../../lib/auth';
import { createTask, assignTask } from '../lib/queries';
import { Task, AssignmentError } from '../../lib/types';

const router = new Router();

router.post('/tasks/assign', async (req) => {
  const user = await requireUser(req);
  const session = await getSession(req);

  if (!user || !session) {
    return new Response(JSON.stringify({ error: 'Unauthorized' }), { status: 401 });
  }

  try {
    const body = await req.json();
    const taskData: Partial<Task> = {
      title: body.title,
      description: body.description,
    };

    const createResult = await createTask(taskData);
    if (createResult.isErr()) {
      return new Response(JSON.stringify({ error: 'Failed to create task' }), { status: 500 });
    }

    const taskId = createResult.value.id;
    const assigneeId = body.assigneeId;

    const assignResult = await assignTask(taskId, assigneeId);
    if (assignResult.isErr()) {
      return new Response(JSON.stringify({ error: 'Failed to assign task' }), { status: 500 });
    }

    return new Response(JSON.stringify({ message: 'Task assigned successfully' }), { status: 200 });
  } catch (error) {
    return new Response(JSON.stringify({ error: 'Internal server error' }), { status: 500 });
  }
});

export default router;

// modules/tasks/lib/types.ts
import { Result, ok, err } from '../../lib/result';

export interface Task {
  id: number;
  title: string;
  description: string;
}

export enum AssignmentError {
  DatabaseFailure = 'Database failure',
  TaskNotFound = 'Task not found',
  AssigneeNotInTaskTeam = 'Assignee is not in the task team',
}

